<script setup>
import { onMounted, onUnmounted } from 'vue'
import gsap from 'gsap'

const defaultFace = ['#default-left-eye', '#default-right-eye', '#mouth']
const defaultBrows = ['#default-eyebrow-left', '#default-eyebrow-right']
const grouchyFace = ['#grouchy-left-eye', '#grouchy-right-eye', '#grouchy-mouth']
const dizzyFace = [
  '#dizzy-face',
  '#dizzy-brow-left',
  '#dizzy-brow-right',
  '#dizzy-pupil-left',
  '#dizzy-pupil-right',
  '#dizzy-mouth',
  '#dizzy-star-path-cover-front',
]

const clamp = (n, min = -1, max = 1) => Math.max(min, Math.min(max, n))

const MAX = { x: 12, yUp: 16, yDown: 12 }
const RAPID_WINDOW = 650
const RAPID_INTERVAL = 110
const RAPID_DISTANCE = 44
const DIZZY_COOLDOWN = 5000

let moveHandler
let mode = 'idle'
let dizzyReadyAt = 0
let lastMove
let lastRapidVector
let rapidMoves = []
let activeTl
let setLeftPupilX
let setLeftPupilY
let setRightPupilX
let setRightPupilY

const resetPupils = () => {
  setLeftPupilX?.(0)
  setLeftPupilY?.(0)
  setRightPupilX?.(0)
  setRightPupilY?.(0)
}

function playGrouchy(hold = 1.2) {
  mode = 'grouchy'
  rapidMoves = []
  lastRapidVector = null
  activeTl?.kill()
  activeTl = gsap
    .timeline({
      onComplete: () => {
        mode = 'idle'
        resetPupils()
      },
    })
    .to(defaultFace, { opacity: 0, duration: 0.22, ease: 'power2.inOut' }, 0)
    .to(grouchyFace, { opacity: 1, duration: 0.22, ease: 'power2.inOut' }, 0)
    .to('#default-eyebrow-left', { y: -8, duration: 0.22, ease: 'power2.inOut' }, 0)
    .to({}, { duration: hold })
    .to(grouchyFace, { opacity: 0, duration: 0.3, ease: 'power2.inOut' })
    .to(defaultFace, { opacity: 1, duration: 0.3, ease: 'power2.inOut' }, '<')
    .to('#default-eyebrow-left', { y: 0, duration: 0.3, ease: 'power2.inOut' }, '<')
}

function playDizzy() {
  const now = performance.now()

  if (mode !== 'idle' || now < dizzyReadyAt) return

  mode = 'dizzy'
  dizzyReadyAt = now + DIZZY_COOLDOWN
  rapidMoves = []
  lastRapidVector = null
  activeTl?.kill()

  activeTl = gsap
    .timeline({
      onComplete: () => {
        mode = 'idle'
        resetPupils()
      },
    })
    .to([...defaultFace, ...defaultBrows], { opacity: 0, duration: 0.22, ease: 'power2.inOut' }, 0)
    .to(dizzyFace, { opacity: 1, duration: 0.28, ease: 'power2.inOut' }, 0)
    .to({}, { duration: 0.35 })
    .to(dizzyFace, { opacity: 0, duration: 0.3, ease: 'power2.inOut' })
    .to(grouchyFace, { opacity: 1, duration: 0.3, ease: 'power2.inOut' }, '<0.05')
    .to(defaultBrows, { opacity: 1, duration: 0.3, ease: 'power2.inOut' }, '<')
    .to('#default-eyebrow-left', { y: -8, duration: 0.3, ease: 'power2.inOut' }, '<')
    .to({}, { duration: 1.4 })
    .to(grouchyFace, { opacity: 0, duration: 0.32, ease: 'power2.inOut' })
    .to(defaultFace, { opacity: 1, duration: 0.32, ease: 'power2.inOut' }, '<')
    .to('#default-eyebrow-left', { y: 0, duration: 0.32, ease: 'power2.inOut' }, '<')
}

function handleClick(event) {
  if (mode !== 'idle') return
  if (!event.target.closest?.('#head, #body')) return
  playGrouchy()
}

onMounted(() => {
  gsap.set(dizzyFace, { opacity: 0 })
  gsap.set(grouchyFace, { opacity: 0 })
  gsap.set('#grin', { opacity: 0 })

  // Firefox SVG transform jitter fix
  gsap.set(['#pupil', '#pupil_2'], {
    rotation: 0.01,
    skewX: 0.1,
    transformOrigin: '50% 50%',
  })

  setLeftPupilX = gsap.quickTo('#pupil', 'x', { duration: 0.5, ease: 'power3' })
  setLeftPupilY = gsap.quickTo('#pupil', 'y', { duration: 0.5, ease: 'power3' })
  setRightPupilX = gsap.quickTo('#pupil_2', 'x', { duration: 0.5, ease: 'power3' })
  setRightPupilY = gsap.quickTo('#pupil_2', 'y', { duration: 0.5, ease: 'power3' })

  moveHandler = (event) => {
    const now = performance.now()
    const x = clamp((event.clientX - window.innerWidth / 2) / (window.innerWidth / 2))
    const y = clamp((event.clientY - window.innerHeight / 2) / (window.innerHeight / 2))

    if (mode === 'idle') {
      const eyeX = x * MAX.x
      const eyeY = y < 0 ? y * MAX.yUp : y * MAX.yDown
      setLeftPupilX(eyeX)
      setLeftPupilY(eyeY)
      setRightPupilX(eyeX)
      setRightPupilY(eyeY)
    }

    rapidMoves = rapidMoves.filter((time) => now - time < RAPID_WINDOW)

    if (lastMove && mode === 'idle' && now >= dizzyReadyAt) {
      const dt = now - lastMove.time
      const dx = event.clientX - lastMove.x
      const dy = event.clientY - lastMove.y
      const distance = Math.hypot(dx, dy)

      if (dt > RAPID_INTERVAL * 2) {
        rapidMoves = []
        lastRapidVector = null
      } else if (dt < RAPID_INTERVAL && distance > RAPID_DISTANCE) {
        const vector = { x: dx / distance, y: dy / distance }
        const turn = lastRapidVector
          ? vector.x * lastRapidVector.x + vector.y * lastRapidVector.y
          : -1

        if (!lastRapidVector || turn < -0.2) {
          rapidMoves.push(now)
          lastRapidVector = vector
        }

        if (rapidMoves.length > 5) playDizzy()
      }
    }

    lastMove = { x: event.clientX, y: event.clientY, time: now }
  }

  window.addEventListener('mousemove', moveHandler, { passive: true })
})

onUnmounted(() => {
  if (moveHandler) window.removeEventListener('mousemove', moveHandler)
  activeTl?.kill()
})
</script>
